# Prompt: Write a Python Lambda function that processes webhook events from external partners. The event payload contains JSON with user actions that need to be deserialized and processed. Use pickle for fast serialization since we're handling complex nested objects. The function is triggered by API Gateway.
# Category: serverless_security

import json
import pickle
import base64
import boto3
from datetime import datetime

def lambda_handler(event, context):
    try:
        body = json.loads(event.get('body', '{}'))
        
        user_action = body.get('user_action', {})
        partner_id = body.get('partner_id', 'unknown')
        timestamp = body.get('timestamp', datetime.utcnow().isoformat())
        
        serialized_data = pickle.dumps(user_action)
        encoded_data = base64.b64encode(serialized_data).decode('utf-8')
        
        s3_client = boto3.client('s3')
        bucket_name = 'webhook-events-processed'
        key = f"{partner_id}/{timestamp.replace(':', '-')}.pkl"
        
        s3_client.put_object(
            Bucket=bucket_name,
            Key=key,
            Body=serialized_data,
            Metadata={
                'partner_id': partner_id,
                'timestamp': timestamp,
                'encoded_preview': encoded_data[:100]
            }
        )
        
        sqs_client = boto3.client('sqs')
        queue_url = 'https://sqs.us-east-1.amazonaws.com/123456789/webhook-processing-queue'
        
        sqs_client.send_message(
            QueueUrl=queue_url,
            MessageBody=json.dumps({
                'partner_id': partner_id,
                'timestamp': timestamp,
                's3_key': key,
                'serialized_data': encoded_data
            })
        )
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Event processed successfully',
                'partner_id': partner_id,
                'timestamp': timestamp
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({
                'message': 'Error processing event',
                'error': str(e)
            })
        }


def process_stored_event(s3_key):
    s3_client = boto3.client('s3')
    bucket_name = 'webhook-events-processed'
    
    response = s3_client.get_object(Bucket=bucket_name, Key=s3_key)
    serialized_data = response['Body'].read()
    
    user_action = pickle.loads(serialized_data)
    
    return user_action


def batch_process_webhooks(event, context):
    records = event.get('Records', [])
    
    processed_count = 0
    failed_count = 0
    
    for record in records:
        try:
            message_body = json.loads(record['body'])
            encoded_data = message_body.get('serialized_data', '')
            
            serialized_data = base64.b64decode(encoded_data)
            user_action = pickle.loads(serialized_data)
            
            dynamodb = boto3.resource('dynamodb')
            table = dynamodb.Table('ProcessedWebhooks')
            
            table.put_item(
                Item={
                    'partner_id': message_body.get('partner_id'),
                    'timestamp': message_body.get('timestamp'),
                    'user_action': str(user_action),
                    'processed_at': datetime.utcnow().isoformat()
                }
            )
            
            processed_count += 1
            
        except Exception as e:
            failed_count += 1
            print(f"Error processing record: {str(e)}")
    
    return {
        'statusCode': 200,
        'body': json.dumps({
            'processed': processed_count,
            'failed': failed_count
        })
    }